import { type ReactNode } from 'react';
import { FormattedMessage } from 'react-intl';

import { _EmptyState as EmptyState } from '@dynatrace/strato-components/charts';

/**
 * @internal
 */
export type DisabledStateProps = { height: string | number };

/**
 * @internal
 */
export const DisabledState = ({ height }: DisabledStateProps) => {
  const messageNode: ReactNode = (
    <FormattedMessage
      id="TXZNTtB5qReH8XE3"
      defaultMessage="Maps have been disabled in your environment - to enable these, please reach out to your environment administrator."
      description="Message to display when all maps are hidden."
    />
  );

  return <EmptyState height={height}>{messageNode}</EmptyState>;
};

DisabledState['displayName'] = 'DisabledState';
